=== Single Number (LC136, Easy) ===
Given a non-empty array where every element appears twice except one, find that one.
class Solution:
    def singleNumber(self, nums):
        x = 0
        for n in nums:
            x ^= n
        return x

=== Set Mismatch (LC645, Easy) ===
Numbers 1..n; one value got duplicated over another (one repeats, one missing). Return [dup, missing].
class Solution:
    def findErrorNums(self, nums):
        s = set(); dup = 0; miss = 0
        for n in nums:
            if n in s: dup = n
            s.add(n)
        for i in range(1, len(nums)+1):
            if i not in s: miss = i
        return [dup, miss]

=== Find All Numbers Disappeared in an Array (LC448, Easy) ===
nums has n ints each in [1,n]; return all values in [1,n] that do not appear.
class Solution:
    def findDisappearedNumbers(self, nums):
        seen = set(nums)
        return [i for i in range(1, len(nums)+1) if i not in seen]

=== Valid Parentheses (LC20, Easy) ===
Given a string of brackets, decide if it is validly matched/nested.
class Solution:
    def isValid(self, s):
        stack = []; pairs = {')':'(', ']':'[', '}':'{'}
        for c in s:
            if c in pairs:
                if not stack or stack.pop() != pairs[c]: return False
            else:
                stack.append(c)
        return not stack

=== Min Stack (LC155, Medium) ===
Stack supporting push/pop/top and getMin in O(1).
class MinStack:
    def __init__(self):
        self.st = []
    def push(self, x):
        m = min(x, self.st[-1][1]) if self.st else x
        self.st.append((x, m))
    def pop(self): self.st.pop()
    def top(self): return self.st[-1][0]
    def getMin(self): return self.st[-1][1]

=== Evaluate Reverse Polish Notation (LC150, Medium) ===
Evaluate a postfix arithmetic expression; division truncates toward zero.
class Solution:
    def evalRPN(self, tokens):
        st = []
        for t in tokens:
            if t in '+-*/' and len(t)==1:
                a, b = st.pop(), st.pop()
                st.append({'+':b+a,'-':b-a,'*':b*a,'/':int(b/a)}[t])
            else:
                st.append(int(t))
        return st[0]

