=== Best Time to Buy and Sell Stock (LC121, Easy) ===
One buy + one sell, maximize profit.
class Solution:
    def maxProfit(self, prices):
        lo = float('inf'); best = 0
        for p in prices:
            lo = min(lo, p)
            best = max(best, p - lo)
        return best

=== Move Zeroes (LC283, Easy) ===
Move all zeroes to the end in place, keep order of non-zeroes.
class Solution:
    def moveZeroes(self, nums):
        i = 0
        for j in range(len(nums)):
            if nums[j] != 0:
                nums[i], nums[j] = nums[j], nums[i]
                i += 1

=== Reverse String (LC344, Easy) ===
Reverse a list of chars in place.
class Solution:
    def reverseString(self, s):
        l, r = 0, len(s)-1
        while l < r:
            s[l], s[r] = s[r], s[l]
            l += 1; r -= 1

=== Container With Most Water (LC11, Medium) ===
Two lines, find max water area between them.
class Solution:
    def maxArea(self, height):
        l, r = 0, len(height)-1; best = 0
        while l < r:
            best = max(best, (r-l) * min(height[l], height[r]))
            if height[l] < height[r]: l += 1
            else: r -= 1
        return best

