Two Sum (LC1): return indices of the two numbers adding to target
class Solution:
    def twoSum(self, nums, target):
        seen = {}
        for i, n in enumerate(nums):
            if target - n in seen:
                return [seen[target-n], i]
            seen[n] = i

Contains Duplicate (LC217): true if any value appears at least twice
class Solution:
    def containsDuplicate(self, nums):
        return len(set(nums)) != len(nums)

Valid Anagram (LC242): is t an anagram of s
class Solution:
    def isAnagram(self, s, t):
        from collections import Counter
        return Counter(s) == Counter(t)
